#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[50001];
        scanf("%s", s);
        int n = strlen(s);
        int left[n], right[n];
        int l = 0, r = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '.') continue;
            int d = s[i] - '0';
            int L = i - d, R = i + d;
            L = L < 0 ? 0 : L;
            R = R >= n ? n - 1 : R;
            int ok = 1;
            for (int j = L; j <= R; j++) {
                if (j == i) continue;
                if (s[j] != '.') {
                    ok = 0;
                    break;
                }
            }
            if (ok) left[l++] = i;
            else {
                ok = 1;
                for (int j = L; j <= R; j++) {
                    if (j == i) continue;
                    if (s[j] != '.') {
                        ok = 0;
                        break;
                    }
                }
                if (ok) right[r++] = i;
                else {
                    printf("unsafe\n");
                    goto next;
                }
            }
        }
        printf("safe\n");
        next:
        continue;
    }
    return 0;
}

